// Query for Anomaly Events
MATCH (a:AnomalyEvent)
WHERE a.asset_name = 'Chiller 9' AND a.timestamp CONTAINS '/20 ' AND a.timestamp STARTS WITH '6/'

// Query for Alert Events
MATCH (al:AlertEvent)-[:FOR_EQUIPMENT]->(e:Equipment {equipment_id: 'CWC04009'})
WHERE al.start_time CONTAINS '/20 ' AND al.start_time STARTS WITH '6/'

// Query for Work Orders
MATCH (wo:WorkOrder)-[:FOR_EQUIPMENT]->(e:Equipment {equipment_id: 'CWC04009'})
WHERE wo.actual_finish CONTAINS '/20 ' AND wo.actual_finish STARTS WITH '6/'

RETURN a.anomaly_key, a.kpi, a.anomaly_score, al.alert_key, al.rule_id, wo.wo_id, wo.wo_description, wo.work_priority
